"""Filename: kg_build_ontology.pyDescription: Initializes the base four-dimensional ontology knowledge graph in Neo4j.             This script establishes the foundational diagnostic nodes and relational             edges (e.g., Components, Failures) before external parameter fusion."""import pandas as pdimport osfrom neo4j import GraphDatabase# ==========================================# Database Configuration# ==========================================URI = "bolt://localhost:7687"USER = "neo4j"# NOTE: Replace 'YOUR_PASSWORD_HERE' with your actual Neo4j password when running locally.# DO NOT commit your real password to the public repository.PASSWORD = os.getenv("NEO4J_PASSWORD", "YOUR_PASSWORD_HERE")def build_ontology_graph():    print("[INFO] Connecting to Neo4j database...")    driver = GraphDatabase.driver(URI, auth=(USER, PASSWORD))    with driver.session() as session:        # --- Step 1: Create Constraints ---        print("[INFO] Creating constraints for entity uniqueness...")        try:            session.run("CREATE CONSTRAINT ON (n:Entity) ASSERT n.name IS UNIQUE")        except Exception as e:            print("[WARN] Constraint might already exist. Proceeding...")        # --- Step 2: Import Ontology Nodes (The Base Skeleton) ---        print("[INFO] Importing structural ontology nodes from raw data...")        try:            nodes_df = pd.read_csv('../Data/New_Ontology_Nodes.csv')            node_query = """            UNWIND $batch AS row            MERGE (n:Entity {name: row.Entity})            SET n.label = row.Label            // Dynamically assign secondary labels based on ontology categorization            FOREACH (ignore IN CASE WHEN row.Label = 'CarModel' THEN [1] ELSE [] END | SET n:CarModel)            FOREACH (ignore IN CASE WHEN row.Label = 'Unit' THEN [1] ELSE [] END | SET n:Unit)            FOREACH (ignore IN CASE WHEN row.Label = 'Feature' THEN [1] ELSE [] END | SET n:Feature)            FOREACH (ignore IN CASE WHEN row.Label = 'Failure' THEN [1] ELSE [] END | SET n:Failure)            FOREACH (ignore IN CASE WHEN row.Label = 'DetectionTool' THEN [1] ELSE [] END | SET n:DetectionTool)            """            session.run(node_query, batch=nodes_df.to_dict('records'))        except FileNotFoundError:            print("[ERROR] New_Ontology_Nodes.csv not found in the Data directory.")        # --- Step 3: Import Ontology Edges ---        print("[INFO] Establishing logical relationships (Edges)...")        try:            edges_df = pd.read_csv('../Data/New_Ontology_Edges.csv')            edge_query = """            UNWIND $batch AS row            MATCH (s:Entity {name: row.Subject})            MATCH (o:Entity {name: row.Object})            // Establish semantic relationships            FOREACH (ignore IN CASE WHEN row.Relation = 'HAS_UNIT' THEN [1] ELSE [] END | MERGE (s)-[:HAS_UNIT]->(o))            FOREACH (ignore IN CASE WHEN row.Relation = 'UNIT_FAILURE' THEN [1] ELSE [] END | MERGE (s)-[:UNIT_FAILURE]->(o))            FOREACH (ignore IN CASE WHEN row.Relation = 'FEATURE_FAILURE' THEN [1] ELSE [] END | MERGE (s)-[:FEATURE_FAILURE]->(o))            FOREACH (ignore IN CASE WHEN row.Relation = 'DETECTS' THEN [1] ELSE [] END | MERGE (s)-[:DETECTS]->(o))            FOREACH (ignore IN CASE WHEN row.Relation = 'COMPOSED_OF' THEN [1] ELSE [] END | MERGE (s)-[:COMPOSED_OF]->(o))            """            session.run(edge_query, batch=edges_df.to_dict('records'))        except FileNotFoundError:            print("[ERROR] New_Ontology_Edges.csv not found in the Data directory.")        # --- Step 4: Validate Graph Construction ---        nodes_count = session.run("MATCH (n) RETURN count(n)").single()[0]        edges_count = session.run("MATCH ()-[r]->() RETURN count(r)").single()[0]        print("-" * 50)        print("[SUCCESS] Base Ontology Graph Construction Completed.")        print(f"Total Nodes: {nodes_count}")        print(f"Total Edges: {edges_count}")        print("-" * 50)    driver.close()if __name__ == "__main__":    build_ontology_graph()